# requires: pip install pytest-recording vcrpy
import pytest
from ragapp.rerank import cohere_rerank


@pytest.fixture
def vcr_config():
    return {
        "filter_headers": [("authorization", "REDACTED")],
        "record_mode": "once",   # 'new_episodes' to add to existing cassette
    }


@pytest.mark.vcr
def test_rerank_returns_sorted_results():
    results = cohere_rerank(
        query="what is HNSW?",
        docs=["a tree structure", "hierarchical NSW graph", "unrelated"],
        top_k=2,
    )
    assert len(results) == 2
    assert "hierarchical NSW" in results[0].text
